        log.info("In outer");
        log.section("Inner", |log| {
            log.info("In inner");
        });
    });

    let output = String::from_utf8(buffer).unwrap();
    // Verify indentation increases
    let outer_indent = output.find("In outer").unwrap() - output[..output.find("In outer").unwrap()].rfind('\n').unwrap_or(0);
    let inner_indent = output.find("In inner").unwrap() - output[..output.find("In inner").unwrap()].rfind('\n').unwrap_or(0);
    assert!(inner_indent > outer_indent);
}

