fn test_timing() {
    let mut logger = TestLogger::new();
    logger.start_timing();
    std::thread::sleep(Duration::from_millis(10));
    let duration = logger.stop_timing();
    assert!(duration >= Duration::from_millis(10));
}

#[test]
fn test_level_filtering() {
    let mut buffer = Vec::new();
    let mut logger = TestLogger::new()
        .with_output(Cursor::new(&mut buffer))
        .with_level(LogLevel::Warn);

    logger.debug("debug message");
    logger.info("info message");
    logger.warn("warn message");
    logger.error("error message");

    let output = String::from_utf8(buffer).unwrap();
    assert!(!output.contains("debug message"));
    assert!(!output.contains("info message"));
    assert!(output.contains("warn message"));
    assert!(output.contains("error message"));
}

#[test]
fn test_thread_safety() {
    let logger = SharedLogger::new(TestLogger::new().with_output(std::io::sink()));

    let handles: Vec<_> = (0..10).map(|i| {
        let logger = logger.clone();
        std::thread::spawn(move || {
            for j in 0..100 {
                logger.lock().info(&format!("Thread {} msg {}", i, j));
            }
        })
    }).collect();

    for h in handles {
        h.join().unwrap();
    }
    // No panics = success
}

#[test]
fn test_ansi_debug() {
    let mut buffer = Vec::new();
    let mut logger = TestLogger::new()
        .with_output(Cursor::new(&mut buffer));

    logger.ansi_debug("styled", "\x1b[31;1mHello\x1b[0m");

    let output = String::from_utf8(buffer).unwrap();
    assert!(output.contains("31")); // Red code
    assert!(output.contains("1"));  // Bold code
}
