#[cfg(test)]
mod basic_derive_tests {
    use bubbletea_macros::Model;
    use bubbletea::Cmd;

    #[test]
    fn test_basic_derive_compiles() {
        #[derive(Model)]
        struct Counter {
            count: i32,
        }

        enum Msg { Increment }

        impl Counter {
            fn update(&mut self, msg: Msg) -> Cmd<Msg> {
                match msg {
                    Msg::Increment => self.count += 1,
                }
                Cmd::none()
            }

            fn view(&self) -> String {
                format!("Count: {}", self.count)
            }
        }

        let model = Counter { count: 0 };
        assert!(model.init().is_none());
    }

    #[test]
    fn test_derive_with_generics() {
        #[derive(Model)]
        struct Container<T> {
            value: T,
        }

        let _model: Container<i32> = Container { value: 42 };
    }

    #[test]
    fn test_derive_with_lifetime() {
        #[derive(Model)]
        struct Borrowed<'a> {
            text: &'a str,
        }

        let text = "hello";
        let _model = Borrowed { text };
    }
}
