    fn arb_sgr_sequence()(
        params in prop::collection::vec(arb_sgr_param(), 1..5)
    ) -> Vec<u8> {
        let mut bytes = vec![0x1B, b'['];
        for (i, p) in params.iter().enumerate() {
            if i > 0 { bytes.push(b';'); }
            bytes.extend(p.to_string().as_bytes());
        }
        bytes.push(b'm');
        bytes
    }
}
